sp_widget.client_script:
api.controller=function($scope, $location, $rootScope,spModal,$uibModal, spUtil, amb, $timeout) {
  /* widget controller */
  var c = this;
	var selectedTaskTypeId;
	var objSelectedType;
	main();
	function main(){
		// this will later load from default value or last selected
		objSelectedType = c.data.taskerTypes.filter(function(o){
			// see script include TaskerWidgetIconsAndMessages to see how saved and loaded
			return o.title == c.data.settings.defaultTaskType;
		})[0];
		_loadFormWidget();
	}

	$scope.selectType= function(sys_id){
		var previous_sys_id = c.data.selected_id;
		objSelectedType = c.data.taskerTypes.filter(function(o){
			return o.sys_id == sys_id;
		})[0];
		// for now, if the item isn't in task types, check advanced
		// we may want to change to put all in a broader array when we put
		// advanced into the type list
		if(!objSelectedType){
			objSelectedType = c.data.advancedTaskerTypes.filter(function(o){
				return o.sys_id == sys_id;
			})[0];
		}
		c.data.selected_id = objSelectedType.sys_id;
		_loadFormWidget();
		if(previous_sys_id != c.data.selected_id){
			// TODO: multi-language - this should become sys_id here and where saved for localization
			$scope.data.defaultTaskTypeUpdated = true;
			$scope.data.settings.defaultTaskType = objSelectedType.title;
			spUtil.update($scope);
		}
	}

	function _loadFormWidget(){
		if(objSelectedType){
			// reset load query each time
			var loadQuery = c.data.query;
			// NOTE: if loading advanced from table this would change
			if(objSelectedType.sys_id != "active_unique"){
				// for all items except advanced, reset tasker type id on selection
				selectedTaskTypeId= objSelectedType.sys_id;
			}
			if(selectedTaskTypeId){
				loadQuery = loadQuery + "^tasker_type="	+ selectedTaskTypeId +
					"^u_servicenow_form_view=" + objSelectedType.sn_view;
			}
			// set loadID above when not advanced, then set query if an ID is set so advanced gets last selected quick type
			c.data.selected_id = objSelectedType.sys_id;
			var form_widget_parameters = {
				table: 'x_153465_discovert_route_task_instance',
				sys_id: -1,
				sys_id_required: false,
				// NOTE: load based on getting user last selection
				view: objSelectedType.sn_view,
				omitHeader: c.data.omitHeader,
				omitHeaderOptions: c.data.omitHeaderOptions,
				query:  loadQuery,
				bifold:c.data.bifold,
				isModal:c.data.isModal,
				shared: {}


			};
			spUtil.get('discovertasker-formtab', form_widget_parameters).then(function(response) {
				c.data.new_task_widget_form = response;
			});
		}
	}
};

sp_widget.css:
.flex-container {
