*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// 2.8 | 2022-05-05 | raj  | STRY0119569 - As a Tasker User, I want to be able to select different form views on New Task Form.
//											New widget built to handle creating new tasks based on task type
//------------------------------------------------------------------------------------------------------------------------
(function($sp, input, data, options, gs) {
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */

	main();
	function main(){
		// if messages not loaded, load messages
		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('new_tasker_selection');

		// save form view preference
		if(input && input.defaultTaskTypeUpdated){
			taskWidgetIconsAndMessage.savePreferenceDefaultTaskType(input.settings.defaultTaskType);
		}

		// load messages
		data.messages = taskWidgetIconsAndMessage.loadMessages();
		// load settings
		data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);

		data.advancedTaskerTypes = _loadAdvancedTypes();
		data.taskerTypes = _loadStandardTypes();

		data.bifold = (input || {}).bifold || (options || {}).bifold || false;		
		data.isModal = (input || {}).isModal || (options || {}).isModal || false;
		data.omit_icons = (input || {}).omit_icons || (options || {}).omit_icons || false;
		data.omitHeader = (input || {}).omitHeader || (options || {}).omitHeader || false;
		data.omitHeaderOptions = (input || {}).omitHeaderOptions || (options || {}).omitHeaderOptions || false;

		data.query  = (input || {}).query || (options || {}).query || "";
		_convertToBool(['isModal', 'omit_icons']);		
	}

	function _loadAdvancedTypes(){
		// only one for now
		var taskTypes = [];
		// TODO: if this view will be configurable eventually, 
		//       then we should add a column to type table for "is advanced"
		//       that way we can separate them differently and load with a filter
		//       against the table rather than hard corded for advanced
		//       To do this, we would need to update places where we pull the list of task types
		//       we need to create some dynamic filter for types, so it might be a 
		//       good time to do both.
		var tasktype = 
				{sys_id: "active_unique",
				 icon:"", 
				 description: data.messages["Tasker - Change to Advance Task view at any time"],
				 title: data.messages["Tasker - Advanced Task"],
				 sn_view: 'sp'};
		taskTypes.push(tasktype);
		return taskTypes;
	}	
	function _loadStandardTypes(){
		var taskTypes = [];
		var tasktype = {icon:"", description:"", title:""};
		var gr_task_Types = new GlideRecord("x_153465_discovert_tasker_type");
		gr_task_Types.addQuery("active", true);
		gr_task_Types.orderBy("order");
		gr_task_Types.query();
		while(gr_task_Types.next()){
			tasktype = 
				{sys_id: gr_task_Types.getUniqueValue(),
				 icon:"", 
				 description:"", // coming soon...title
				 title: gr_task_Types.getDisplayValue("tasker_type"),
				 sn_view: gr_task_Types.getDisplayValue("u_servicenow_form_view")
				};
			taskTypes.push(tasktype);

		}
		return taskTypes;
	}

	function _convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}
})($sp, input, data, options, gs);
